// packages/extension-sdk/src/platform.ts
function getPlatformConfig(context, platformName) {
  const platform = context.config?.platform;
  if (!platform || typeof platform !== "object") {
    return {};
  }
  const value = platform[platformName];
  if (!value || typeof value !== "object") {
    return {};
  }
  return value;
}
function definePlatformFactory(options) {
  return async (context) => {
    const raw = getPlatformConfig(context, options.platformName);
    const config = options.resolveConfig(raw, context);
    return await options.create(context.backend, config, context);
  };
}
// packages/extension-sdk/src/logger.ts
function print(level, scope, args) {
  const consoleMethod = console[level] ?? console.log;
  consoleMethod(`[${scope}]`, ...args);
}
function createExtensionLogger(extensionName, tag) {
  const scope = tag ? `${extensionName}:${tag}` : extensionName;
  return {
    info: (...args) => print("log", scope, args),
    warn: (...args) => print("warn", scope, args),
    error: (...args) => print("error", scope, args),
    debug: (...args) => print("debug", scope, args)
  };
}
// packages/extension-sdk/src/pairing/store.ts
var logger = createExtensionLogger("ExtensionSDK", "PairingStore");
// extensions/lark/src/card-builder.ts
var TOOL_STATUS_ICONS = {
  queued: "⏳",
  executing: "\uD83D\uDD27",
  success: "✅",
  error: "❌",
  streaming: "\uD83D\uDCE1",
  awaiting_approval: "\uD83D\uDD10",
  awaiting_apply: "\uD83D\uDCCB",
  warning: "⚠️"
};
var TOOL_STATUS_LABELS = {
  queued: "等待中",
  executing: "执行中",
  success: "成功",
  error: "失败",
  streaming: "输出中",
  awaiting_approval: "等待审批",
  awaiting_apply: "等待应用",
  warning: "警告"
};
function buildLarkCard(state, data = {}) {
  switch (state) {
    case "thinking":
      return buildThinkingCard();
    case "streaming":
      return buildStreamingCard(data.text ?? "", data.toolEntries ?? []);
    case "complete":
      return buildCompleteCard(data.text ?? "", data.toolEntries ?? [], data.isError, data.isAborted);
  }
}
function buildThinkingCard() {
  return {
    config: { wide_screen_mode: true, update_multi: true },
    elements: [{
      tag: "markdown",
      content: "\uD83D\uDCAD 思考中..."
    }]
  };
}
function buildStreamingCard(text, toolEntries) {
  const elements = [];
  if (text) {
    elements.push({ tag: "markdown", content: text });
  }
  if (toolEntries.length > 0) {
    const toolLines = toolEntries.map((entry) => formatLarkToolLine(entry)).join(`
`);
    elements.push({ tag: "markdown", content: toolLines, text_size: "notation" });
  }
  if (elements.length === 0) {
    elements.push({ tag: "markdown", content: "\uD83D\uDCAD 思考中..." });
  }
  return {
    config: { wide_screen_mode: true, update_multi: true },
    elements
  };
}
function buildCompleteCard(text, toolEntries, isError, isAborted) {
  const elements = [];
  elements.push({ tag: "markdown", content: text || "（无内容）" });
  if (toolEntries.length > 0) {
    const toolLines = toolEntries.filter((entry) => entry.status === "success" || entry.status === "error").map((entry) => formatLarkToolLine(entry)).join(`
`);
    if (toolLines) {
      elements.push({ tag: "markdown", content: toolLines, text_size: "notation" });
    }
  }
  if (isError) {
    elements.push({ tag: "markdown", content: "<font color='red'>出错</font>", text_size: "notation" });
  } else if (isAborted) {
    elements.push({ tag: "markdown", content: "⏹ 已停止", text_size: "notation" });
  }
  return {
    config: { wide_screen_mode: true, update_multi: true },
    elements
  };
}
function formatLarkToolLine(entry) {
  const icon = TOOL_STATUS_ICONS[entry.status] ?? "⏳";
  const label = TOOL_STATUS_LABELS[entry.status] ?? entry.status;
  return `${icon} \`${entry.toolName}\` ${label}`;
}

